sql:
SELECT department_id, COUNT(unit_id) AS unit_count
FROM units
GROUP BY department_id;

external_knowledge:
- 'Ships' metaphorically refers to the different units;
- 'Passengers' metaphorically refers to the students enrolled in each unit;
- 'Welcomed aboard' indicates the number of enrollments in each unit.

sql:
SELECT unit_id, COUNT(*) as student_count
FROM unit_enrollments
GROUP BY unit_id;

SELECT u.unit_code, u.title, e.student_id, e.status
FROM units u
INNER JOIN unit_enrollments e ON u.unit_id = e.unit_id;

SELECT unit_id, title, level, term, academic_year 
FROM units
WHERE unit_id = '0';

SELECT student_id 
FROM unit_enrollments 
WHERE unit_id = '1';

SELECT COUNT(*) 
FROM unit_enrollments 
WHERE student_id = 'student_id_here';
